        boolean isSurrogate = Character.isHighSurrogate(ch) && i + 1 < csLen && Character.isLowSurrogate(cs.charAt(i + 1));
        if (isSurrogate) {
            int codePoint = Character.toCodePoint(ch, cs.charAt(i + 1));
            for (int j = 0; j < searchLen; j++) {
                    if (Character.isHighSurrogate(searchChars[j]) && j + 1 < searchLen
                            && Character.isLowSurrogate(searchChars[j + 1])) {
                        int searchCodePoint = Character.toCodePoint(searchChars[j], searchChars[j + 1]);
                        if (codePoint == searchCodePoint) {
                            i++; // Move position forward as a surrogate pair
                            continue outer;
                        }
                    }
            }
            return i; // surrogate pair not found
        } else { // handle regular characters
            for (int j = 0; j < searchLen; j++) {
                if (searchChars[j] == ch) {
                    continue outer;
                }
            }
            return i;
        }
    }
    return INDEX_NOT_FOUND;
}

public static int indexOfAnyBut(CharSequence cs, char[] searchChars) {
    if (cs == null || cs.length() == 0 || searchChars == null || searchChars.length == 0) {
        return -1;
    }
    int csLen = cs.length();
    int searchLen = searchChars.length;
    outer:
    for (int i = 0; i < csLen; i++) {
        int ch = Character.codePointAt(cs, i);
        int charCount = Character.charCount(ch);
        for (int j = 0; j < searchLen; j++) {
            if (Character.codePointAt(searchChars, j) == ch) {
                i += charCount - 1; // skip surrogate pairs
                continue outer;
            }
        }
        return i;
    }
    return -1;
}
